# Task management module with task tracking

# Task class with explicit constructor
class Task:
    name: str
    duration: int  # in minutes
    priority: int  # 1-5, higher is more urgent

    def __init__(self, name: str, duration: int, priority: int):
        self.name = name
        self.duration = duration
        self.priority = priority

# in-memory task storage
_tasks: list[Task] = []

def add_task(name: str, duration: int, priority: int) -> None:
    task = Task(name, duration, priority)
    _tasks.append(task)

def get_all_tasks() -> list[Task]:
    return _tasks.copy()

def get_total_duration() -> int:
    total: int = 0
    for task in _tasks:
        total += task.duration
    return total

def get_high_priority_count() -> int:
    count: int = 0
    for task in _tasks:
        if task.priority >= 4:
            count += 1
    return count

def clear_tasks() -> None:
    _tasks.clear()
